import React, { useState, useEffect } from 'react';
import axios from 'axios';

const Electronics = () => {
  const [posts, setPosts] = useState([]);
  const [selectedPost, setSelectedPost] = useState(null);
  const [loading, setLoading] = useState(true);

  const BASE_URL = 'http://localhost:5001';

  useEffect(() => {
    const fetchPosts = async () => {
      try {
        const res = await axios.get(`${BASE_URL}/api/blog/Electronics`);
        setPosts(res.data);
        // By default, pehla post select kar lo
        if (res.data.length > 0) {
          setSelectedPost(res.data[0]);
        }
      } catch (err) {
        console.error("Error fetching electronics posts:", err);
      } finally {
        setLoading(false);
      }
    };
    fetchPosts();
  }, []);

  const getImageUrl = (imagePath) => {
    if (!imagePath) return null;
    const cleanPath = imagePath.startsWith('/') ? imagePath : `/${imagePath}`;
    return `${BASE_URL}${cleanPath}`;
  };

  if (loading) {
    return (
      <div className="h-screen flex items-center justify-center bg-white">
        <div className="w-12 h-12 border-4 border-orange-500 border-t-transparent rounded-full animate-spin"></div>
      </div>
    );
  }

  return (
    <div className="bg-white min-h-screen">
      {/* Header */}
      <header className="pt-20 pb-10 px-6 md:px-16 bg-[#0f172a] text-white">
        <div className="max-w-7xl mx-auto">
          <span className="text-orange-500 font-black text-xs uppercase tracking-widest mb-2 block">Knowledge Base</span>
          <h1 className="text-4xl md:text-5xl font-black tracking-tighter">Electronics <span className="text-orange-500">Insights</span></h1>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-6 py-12">
        <div className="flex flex-col lg:flex-row gap-12">

          {/* LEFT SIDE: COMPLETE BLOG DISPLAY */}
          <div className="lg:w-2/3">
            {selectedPost ? (
              <article className="animate-fadeIn">
                <div className="rounded-[2rem] overflow-hidden bg-gray-100 mb-8 shadow-xl">
                  <img 
                    src={getImageUrl(selectedPost.image)} 
                    alt={selectedPost.title}
                    className="w-full h-[400px] object-cover"
                    onError={(e) => { e.target.src = "https://via.placeholder.com/800x400?text=No+Image+Available"; }}
                  />
                </div>

                <div className="flex items-center gap-4 mb-6">
                  <span className="px-3 py-1 bg-orange-100 text-orange-600 text-[10px] font-bold uppercase rounded-full">
                    Electronics
                  </span>
                  <span className="text-gray-400 text-sm">
                    {new Date(selectedPost.createdAt).toLocaleDateString('en-GB', { day: 'numeric', month: 'long', year: 'numeric' })}
                  </span>
                </div>

                <h2 className="text-4xl md:text-5xl font-black text-gray-900 mb-8 leading-tight">
                  {selectedPost.title}
                </h2>

                <div className="prose prose-lg max-w-none text-gray-600 leading-relaxed space-y-6">
                  {/* Agar aapke paas lamba content hai toh paragraphs mein split kar sakte hain */}
                  {selectedPost.description.split('\n').map((para, i) => (
                    <p key={i} className="text-xl">{para}</p>
                  ))}
                </div>
              </article>
            ) : (
              <div className="text-center py-20 text-gray-300">No post selected</div>
            )}
          </div>

          {/* RIGHT SIDE: TITLES LIST (STICKY) */}
          <div className="lg:w-1/3">
            <div className="sticky top-10">
              <h3 className="text-xs font-black uppercase tracking-[0.2em] text-gray-400 mb-6 border-b pb-4">
                Latest Reports
              </h3>
              <div className="space-y-4">
                {posts.map((post) => (
                  <div 
                    key={post._id}
                    onClick={() => {
                      setSelectedPost(post);
                      window.scrollTo({ top: 0, behavior: 'smooth' });
                    }}
                    className={`p-6 rounded-2xl cursor-pointer transition-all duration-300 border-2 ${
                      selectedPost?._id === post._id 
                      ? 'border-orange-500 bg-orange-50 shadow-lg translate-x-2' 
                      : 'border-transparent hover:bg-gray-50'
                    }`}
                  >
                    <h4 className={`font-bold leading-snug ${
                      selectedPost?._id === post._id ? 'text-orange-600' : 'text-gray-800'
                    }`}>
                      {post.title}
                    </h4>
                    <p className="text-xs text-gray-400 mt-2">
                      {new Date(post.createdAt).toLocaleDateString()}
                    </p>
                  </div>
                ))}
              </div>

              {/* Sidebar CTA */}
              <div className="mt-12 p-8 bg-gray-900 rounded-[2rem] text-white">
                <h4 className="text-xl font-bold mb-4">Need help?</h4>
                <p className="text-gray-400 text-sm mb-6">Contact our electronics experts for custom solutions.</p>
                <button className="w-full py-3 bg-orange-600 rounded-xl font-bold hover:bg-orange-700 transition-colors">
                  Contact Us
                </button>
              </div>
            </div>
          </div>

        </div>
      </main>
    </div>
  );
};

export default Electronics;
